            $this->username = $this->normalize_string($settings['username'] ?? '');
            $this->password = $this->normalize_string($settings['password'] ?? '');
            $this->dbid = $this->normalize_int($settings['dbid'] ?? 0, 0);
            $this->persistent = !empty($settings['persistent']);
            $this->default_ttl = $this->normalize_int($settings['default_ttl'] ?? ($settings['default_lifetime'] ?? 360), 360);
            $this->redis_connect_timeout = $this->normalize_float($settings['redis_connect_timeout'] ?? 1.0, 1.0);
            $this->redis_read_timeout = $this->normalize_float($settings['redis_read_timeout'] ?? ($settings['read_timeout'] ?? 0), 0.0);
            $this->allow_unsafe_flushdb = !empty($settings['allow_unsafe_flushdb']) || !empty($settings['allow_flushdb']);
            $this->cache_wp_admin = !empty($settings['cache_wp_admin']);
            $this->store_transients = !empty($settings['store_transients']);
            $this->safe_mode = !empty($settings['safe_mode']) || (defined('FASTPIXEL_CACHE_SAFE_MODE') && FASTPIXEL_CACHE_SAFE_MODE);
            $this->debug_enabled = !empty($settings['debug']) || (defined('FASTPIXEL_CACHE_DEBUG') && FASTPIXEL_CACHE_DEBUG);

            if (array_key_exists('global_groups', $settings)) {
                $this->global_groups = $this->normalize_list($settings['global_groups']);
            }

            if (array_key_exists('non_persistent_groups', $settings) || array_key_exists('do_not_cache', $settings)) {
                $non_persistent = array_key_exists('non_persistent_groups', $settings)
                    ? $settings['non_persistent_groups']
                    : $settings['do_not_cache'];
                $this->non_persistent_groups = $this->normalize_list($non_persistent);
            }

            // this forces WP to skip transients
            if (!$this->store_transients) {
                $this->add_non_persistent_groups(['transient', 'site-transient']);
            }

            // use the keysalt prefix
            if (isset($settings['key_salt']) && is_scalar($settings['key_salt']) && $settings['key_salt'] !== '') {
                $this->key_salt = rtrim((string) $settings['key_salt'], ':') . ':';
            } elseif (defined('WP_CACHE_KEY_SALT')) {
                $this->key_salt = rtrim((string) WP_CACHE_KEY_SALT, ':') . ':';
            }

            $this->setup_prefixes();
