        public function is_healthy(): bool
        {
            if (!$this->connected) {
                $this->update_backend_health(false, 'not-connected');
                return false;
            }

            if ($this->method === 'redis') {
                $healthy = ($this->redis instanceof Redis) && $this->validate_redis_ping($this->redis);
                $this->update_backend_health($healthy, 'healthcheck-redis');
                return $healthy;
            }

            if ($this->method === 'memcached') {
                $healthy = ($this->memcached instanceof Memcached) && $this->memcached_is_healthy($this->memcached);
                $this->update_backend_health($healthy, 'healthcheck-memcached');
                return $healthy;
            }

            $this->update_backend_health(false, 'healthcheck-unknown-method');
            return false;
        }

        
        // add object in database (adds only if the key doesn't already exist)
        public function add($key, $value, $group = 'default', $expiration = 0)
        {
            /*
             * Scenarios
             * (1) - Object is persistent, external cache is available
             * (2) - Object is a transient and the user wants it cached and external cache is not available
             * (3) - Object is simply stored internally
             *
             * See set function for a more detailed overview
             * */

            if ($this->is_cache_addition_suspended()) {
                return false;
            }

            $derived_key = $this->build_key($key, $group);
            $group = $this->normalize_group($group);

            // Scenario (1)
            if ($this->should_persist($group)) {
                $expiration = $this->normalize_expiration($expiration);
                $result = $this->persist_add($derived_key, $value, $expiration);
                // save snapshot internally
                if ($result) {
                    $this->add_to_internal_cache($derived_key, $value);
                }
                return $result;
            }

            // Scenario (2)
            if ($this->can_use_transient_db_fallback($group)) {
                $transient_key = (string) $key;
                $this->log_debug('fallback_to_db_transient', ['operation' => 'add', 'group' => $group, 'key' => $transient_key]);
                if ($this->_transient_get($transient_key, $group) !== false) {
                    return false;
                }

                $expiration = $this->normalize_transient_expiration($this->normalize_expiration($expiration));
                $result = (bool) $this->_transient_set($transient_key, $value, $group, $expiration);
                if ($result) {
                    $this->add_to_internal_cache($derived_key, $value);
                }
                return $result;
            }

            if (array_key_exists($derived_key, $this->cache)) {
                return false;
            }
        
            // add to snapshot
            $this->add_to_internal_cache($derived_key, $value);
            return true;
        }

        public function add_multiple(array $data, $group = 'default', $expiration = 0)
        {
            $results = [];
            foreach ($data as $key => $value) {
                $results[$key] = $this->add($key, $value, $group, $expiration);
            }
            return $results;
        }

        // replace item in database
        public function replace($key, $value, $group = 'default', $expiration = 0)
        {
            /*
             * Scenarios
             * (1) - Object is persistent, external cache is available
             * (2) - Object is a transient and the user wants it cached and external cache is not available
             * (3) - Object is simply stored internally
             *
             * */
            $derived_key = $this->build_key($key, $group);
            $group = $this->normalize_group($group);

            // Scenario 1
            if ($this->should_persist($group)) {
                if (!$this->key_exists($derived_key)) {
                    return false;
                }
                $expiration = $this->normalize_expiration($expiration);
                $result = $this->persist_set($derived_key, $value, $expiration);
                // create a internal snapshot
                if ($result) {
                    $this->add_to_internal_cache($derived_key, $value);
                }
                return $result;
            }

            // fallback for scenario (2)
            if ($this->can_use_transient_db_fallback($group)) {
                $transient_key = (string) $key;
                $this->log_debug('fallback_to_db_transient', ['operation' => 'replace', 'group' => $group, 'key' => $transient_key]);
                if ($this->_transient_get($transient_key, $group) === false) {
                    return false;
                }

                $expiration = $this->normalize_transient_expiration($this->normalize_expiration($expiration));
                $result = (bool) $this->_transient_set($transient_key, $value, $group, $expiration);
                if ($result) {
                    $this->add_to_internal_cache($derived_key, $value);
                }
                return $result;
            }

            // item exists
            if (!array_key_exists($derived_key, $this->cache)) {
                return false;
            }

            // save to cache internally (scenario 3)
            $this->add_to_internal_cache($derived_key, $value);
            return true;
        }

        public function set($key, $value, $group = 'default', $expiration = 0)
        {
            /*
                This is the main entry point for setting, we have three cases.

                1) Set object to persistent cache (redis/memcached)
                2) Handle transient (obscure case)
                3) Set to internal cache (general case)
    
                * 2) only is valid in the scenario where Redis or memcached isn't available
                * it's a safety net, if Redis for instance is down : the transient will be stored internally
                
            */
            // calculate prefixes to store key
            $derived_key = $this->build_key($key, $group);
            $group = $this->normalize_group($group);

            // this fails if the cache is down
            // if this group should persist (1)
            if ($this->should_persist($group)) {
                $expiration = $this->normalize_expiration($expiration);
                $result = $this->persist_set($derived_key, $value, $expiration);
                // if everything is OK, mirror the result to cache
                if ($result) {
                    $this->add_to_internal_cache($derived_key, $value);
                }
                return $result;
            }

            // store transient internally if external cache is down (2)
            if ($this->can_use_transient_db_fallback($group)) {
                $this->log_debug('fallback_to_db_transient', ['operation' => 'set', 'group' => $group, 'key' => (string) $key]);
                $expiration = $this->normalize_transient_expiration($this->normalize_expiration($expiration));
                $result = (bool) $this->_transient_set((string) $key, $value, $group, $expiration);
                if ($result) {
                    $this->add_to_internal_cache($derived_key, $value);
                }
                return $result;
            }

            // general case : no transient, no persistent context just add to cache (3)
            $this->add_to_internal_cache($derived_key, $value);
            return true;
        }

        public function set_multiple(array $data, $group = 'default', $expiration = 0)
        {
            $results = [];
            foreach ($data as $key => $value) {
                $results[$key] = $this->set($key, $value, $group, $expiration);
            }
            return $results;
        }

        // base function for getting a value
        public function get($key, $group = 'default', $force = false, &$found = null)
        {
            $derived_key = $this->build_key($key, $group);
            $group = $this->normalize_group($group);

            // if not force, it verifies the run-time cache
            if (!$force) {
                $cached = $this->get_from_internal_cache($derived_key, $has);
                if ($has) {
                    $found = true;
                    $this->cache_hits++;
                    $this->runtime_hits++;
                    return $cached;
                }
            }

            // misses if the object is not persistent and force persistent is true
            if (!$this->should_persist($group)) {
                // looks for a transient
                if ($this->can_use_transient_db_fallback($group)) {
                    $this->log_debug('fallback_to_db_transient', ['operation' => 'get', 'group' => $group, 'key' => (string) $key]);
                    $fallback = $this->_transient_get((string) $key, $group);
                    if ($fallback !== false) {
                        $found = true;
                        $this->cache_hits++;
                        $this->persistent_hits++;
                        $this->add_to_internal_cache($derived_key, $fallback);
                        return $fallback;
                    }
                }

                $found = false;
                $this->cache_misses++;
                return false;
            }

            // find the value from the external cache
            $value = $this->persist_get($derived_key);
            if ($value === null) {
                $found = false;
                $this->cache_misses++;
                return false;
            }

            $found = true;
            $this->cache_hits++;
            $this->persistent_hits++;
            $value = $this->maybe_unserialize($value);
            $this->add_to_internal_cache($derived_key, $value);
            return $value;
        }
        public function get_multiple($keys, $group = 'default', $force = false)
        {
            if (!is_array($keys)) {
                return false;
            }

            $group = $this->normalize_group($group);
            $results = [];
            $derived_keys = [];
            $remaining_keys = [];

            foreach ($keys as $key) {
                $derived_keys[$key] = $this->build_key($key, $group);
            }

            if (!$force) {
                foreach ($keys as $key) {
                    $cached = $this->get_from_internal_cache($derived_keys[$key], $has);
                    if ($has) {
                        $results[$key] = $cached;
                        $this->cache_hits++;
                        $this->runtime_hits++;
                    } else {
                        $remaining_keys[] = $key;
                    }
                }
            } else {
                $remaining_keys = $keys;
            }

            if (empty($remaining_keys)) {
                return $results;
            }

            if (!$this->should_persist($group)) {
                if ($this->can_use_transient_db_fallback($group)) {
                    foreach ($remaining_keys as $key) {
                        $this->log_debug('fallback_to_db_transient', ['operation' => 'get_multiple', 'group' => $group, 'key' => (string) $key]);
                        $fallback = $this->_transient_get((string) $key, $group);
                        if ($fallback !== false) {
                            $results[$key] = $fallback;
                            $this->add_to_internal_cache($derived_keys[$key], $fallback);
                            $this->cache_hits++;
                            $this->persistent_hits++;
                            continue;
                        }

                        $results[$key] = false;
                        $this->cache_misses++;
                    }
                    return $results;
                }

                foreach ($remaining_keys as $key) {
                    $results[$key] = false;
                    $this->cache_misses++;
                }
                return $results;
            }

            // separate get logic from external cache (redis and memcached)
            $fetched = [];

            if ($this->method === 'memcached' && $this->memcached instanceof Memcached) {
                // set lookup table
                $lookup = [];
                foreach ($remaining_keys as $key) {
                    $lookup[$key] = $derived_keys[$key];
                }

                // inject keys
                $values = $this->memcached->getMulti(array_values($lookup));
                if ($values === false) {
                    $fetched = [];
                } else {
                    if (!is_array($values)) {
                        $values = [];
                    }
                    foreach ($lookup as $key => $derived_key) {
                        if (array_key_exists($derived_key, $values)) {
                            $fetched[$key] = $values[$derived_key];
                        } else {
                            $fetched[$key] = null;
                        }
                    }
                }
            } elseif ($this->redis instanceof Redis) {
                $ids = [];
                foreach ($remaining_keys as $key) {
                    $ids[] = $derived_keys[$key];
                }
                $values = $this->redis->mget($ids);
                if (is_array($values)) {
                    foreach ($remaining_keys as $idx => $key) {
                        $fetched[$key] = $values[$idx] ?? null;
                    }
                }
            }

            if (empty($fetched)) {
                foreach ($remaining_keys as $key) {
                    // if it failed for some reason, we'll get it individually
                    $value = $this->persist_get($derived_keys[$key]);
                    $fetched[$key] = $value;
                }
            }

            foreach ($remaining_keys as $key) {
                $value = $fetched[$key] ?? null;
                if ($value === null) {
                    $results[$key] = false;
                    $this->cache_misses++;
                    // catch miss
                    continue;
                }
                $value = $this->maybe_unserialize($value);
                $results[$key] = $value;
                $this->add_to_internal_cache($derived_keys[$key], $value);
                $this->cache_hits++;
                $this->persistent_hits++;
            }

            return $results;
        }

        public function get_multi($groups)
        {
            // simply calls get multiple times, get_multiple is recommended
            if (empty($groups) || !is_array($groups)) {
                return false;
            }
            $results = [];
            foreach ($groups as $group => $keys) {
                if (!is_array($keys)) {
                    continue;
                }
                foreach ($keys as $key) {
                    $results[$this->build_key($key, $group)] = $this->get($key, $group);
                }
            }
            return $results;
        }

        // delete from persistent and internal
        public function delete($key, $group = 'default', $time = 0)
        {
            $derived_key = $this->build_key($key, $group);
            $group = $this->normalize_group($group);

            // delete from internal cache
            if (array_key_exists($derived_key, $this->cache)) {
                unset($this->cache[$derived_key]);
            }

            $this->ensure_backend_for_admin_maintenance('delete');

            // delete from external cache
            if ($this->should_persist($group)) {
                return $this->persist_delete($derived_key);
            }

            // delete from wp_options transients (remember, only if external cache is down)
            if ($this->can_use_transient_db_fallback($group)) {
                $this->log_debug('fallback_to_db_transient', ['operation' => 'delete', 'group' => $group, 'key' => (string) $key]);
                $this->_transient_del((string) $key, $group);
                return true;
            }

            return true;
        }

        public function delete_multiple(array $keys, $group = 'default')
        {
            // call delete many times
            $results = [];
            foreach ($keys as $key) {
                $results[$key] = $this->delete($key, $group);
            }
            return $results;
        }

        // flush all
        public function flush()
        {
            $this->cache = [];
            $this->group_versions = [];
            $this->ensure_backend_for_admin_maintenance('flush');
            if ($this->should_persist('default')) {
                return $this->persist_flush();
            }
            return true;
        }

        public function flush_group($group)
        {
            $group = $this->sanitize_key_part($this->normalize_group($group));
            $this->flush_runtime_group($group);

            if ($this->is_non_persistent_group($group)) {
                return true;
            }

            $this->ensure_backend_for_admin_maintenance('flush_group');

            // flush that group version by incrementing it. (see the method for more details)
            if ($this->method === 'memcached') {
                if (!$this->connected || !($this->memcached instanceof Memcached)) {
                    if ($this->safe_mode || !$this->reconnect_backend('flush_group_memcached')) {
                        return false;
                    }
                }
                return $this->bump_group_version($group);
            }

            // simply flush it using API
            if ($this->method === 'redis') {
                if (!$this->connected || !($this->redis instanceof Redis)) {
                    if ($this->safe_mode || !$this->reconnect_backend('flush_group_redis')) {
                        return false;
                    }
                }
                return $this->persist_flush_group_redis($group);
            }

            return false;
        }

        public function flush_runtime()
        {
            $this->cache = [];
            return true;
        }

        public function increment($key, $offset = 1, $group = 'default')
        {
            // incrementing is an atomic operation, that's why it's supported as an abstract layer here
            $derived_key = $this->build_key($key, $group);
            $group = $this->normalize_group($group);
            $offset = (int) $offset;

            // if that value is a number, it increments by one

            if ($this->should_persist($group)) {
                $result = $this->persist_incr($derived_key, $offset);
                if ($result !== false) {
                    $this->add_to_internal_cache($derived_key, (int) $result);
                }
                return $result;
            }

            $value = 0;
            $cached = $this->get_from_internal_cache($derived_key, $has);
            if ($has) {
                $value = (int) $cached;
            }
            $value += $offset;
            $this->add_to_internal_cache($derived_key, $value);
            return $value;
        }

        public function incr($key, $offset = 1, $group = 'default')
        {
            return $this->increment($key, $offset, $group);
        }

        public function decrement($key, $offset = 1, $group = 'default')
        {
            // same as increment but decrement
            $derived_key = $this->build_key($key, $group);
            $group = $this->normalize_group($group);
            $offset = (int) $offset;

            if ($this->should_persist($group)) {
                $result = $this->persist_decr($derived_key, $offset);
                if ($result !== false) {
                    $this->add_to_internal_cache($derived_key, (int) $result);
                }
                return $result;
            }

            $value = 0;
            $cached = $this->get_from_internal_cache($derived_key, $has);
            if ($has) {
                $value = (int) $cached;
            }
            $value -= $offset;
            $this->add_to_internal_cache($derived_key, $value);
            return $value;
        }

        public function decr($key, $offset = 1, $group = 'default')
        {
            return $this->decrement($key, $offset, $group);
        }

        public function switch_to_blog($blog_id)
        {
            // feature that allows storing keys on a specific site
            
            // only available for multisite
            if (!function_exists('is_multisite') || !is_multisite()) {
                return false;
            }

            $blog_id = (int) $blog_id;
            if ($blog_id <= 0) {
                $blog_id = 1;
            }

            if ($this->network_prefix === '') {
                $this->setup_prefixes();
            }

            $network_id = 0;
            if (function_exists('get_site')) {
                $site = get_site($blog_id);
                if ($site && isset($site->site_id)) {
                    $network_id = (int) $site->site_id;
                }
            }
            //
            // set a new network id based on that site
            if ($network_id <= 0 && function_exists('get_current_network_id')) {
                $network_id = (int) get_current_network_id();
            }
            if ($network_id > 0) {
                $this->network_prefix = 'network-' . $network_id;
                $this->global_prefix = $this->network_prefix . ':global';
            }

            $this->blog_prefix = $this->network_prefix . ':blog-' . $blog_id;
            return true;
        }

        public function add_global_groups($groups)
        {
            $groups = $this->normalize_list($groups);
            if (!empty($groups)) {
                $this->global_groups = array_values(array_unique(array_merge($this->global_groups, $groups)));
            }
        }

        public function add_non_persistent_groups($groups)
        {
            $groups = $this->normalize_list($groups);
            if (!empty($groups)) {
                $this->non_persistent_groups = array_values(array_unique(array_merge($this->non_persistent_groups, $groups)));
            }
        }

        public function reset()
        {
            return $this->flush_runtime();
        }

        // very usefull for debugging
        public function stats()
        {
            $hits = (int) $this->cache_hits;
            $runtime_hits = (int) $this->runtime_hits;
            $persistent_hits = (int) $this->persistent_hits;
            $misses = (int) $this->cache_misses;
            $ratio = ($hits + $misses) > 0 ? round($hits / (($hits + $misses) / 100), 1) : 100;
            $bytes = 0;
            foreach ($this->cache as $value) {
                $bytes += strlen(serialize($value));
            }

            return [
                'hits' => $hits,
                'runtime_hits' => $runtime_hits,
                'persistent_hits' => $persistent_hits,
                'misses' => $misses,
                'ratio' => $ratio, // hit / miss
                'bytes' => $bytes,
                'time' => $this->cache_time,
            ];
        }

        // aslo very usefull for debugging
        public function info()
        {
            $stats = $this->stats();
            return (object) [
                'hits' => $stats['hits'],
                'runtime_hits' => $stats['runtime_hits'],
                'persistent_hits' => $stats['persistent_hits'],
                'misses' => $stats['misses'],
                'ratio' => $stats['ratio'],
                'bytes' => $stats['bytes'],
                'time' => $stats['time'],
                'groups' => (object) [
                    'global' => $this->global_groups,
                    'non_persistent' => $this->non_persistent_groups,
                ],
            ];
        }

        protected function setup_prefixes()
        {
            // construct network prefixes for a key
            global $blog_id, $table_prefix, $current_site;

            // global is a scope within a network
            // we subdivide in 3 layers.
            // 1. blog (per site)
            // 2. global (per multisite)
            // 3. network (per network)
            // to not risk messed keys

            if (function_exists('is_multisite') && is_multisite()) {
                // it's recommended for multisites spread across networks to use diferent namesapce for keys
                $network_id = 1;
                if (function_exists('get_current_network_id')) {
                    $network_id = (int) get_current_network_id();
                } elseif (isset($current_site->id)) {
                    $network_id = (int) $current_site->id;
                }
                if ($network_id <= 0) {
                    $network_id = 1;
                }

                $site_id = 0;
                if (function_exists('get_current_blog_id')) {
                    $site_id = (int) get_current_blog_id();
                }
                if ($site_id <= 0) {
                    $site_id = !empty($blog_id) ? (int) $blog_id : 1;
                }

                $this->network_prefix = 'network-' . $network_id;
                $this->global_prefix = $this->network_prefix . ':global';
                $this->blog_prefix = $this->network_prefix . ':blog-' . $site_id;
            } else {
                // fallback, not multisite, network is not really releveant here so we use table prefix
                $prefix = isset($table_prefix) ? trim((string) $table_prefix, '_:') : '';
                if ($prefix === '') {
                    $prefix = 'wp';
                }

                // network gets a table prefix
                $this->network_prefix = $prefix;
                $this->global_prefix = $this->network_prefix . ':global';
                $this->blog_prefix = $this->network_prefix . ':blog-1';
            }
        }

        protected function connect($force_admin = false)
        {
            /*
                if admin and not WP_ADMIN option, disable object-caching.
            */
            if (!$force_admin && !$this->cache_wp_admin) {
                $is_admin = (defined('WP_ADMIN') && WP_ADMIN);
                if (!$is_admin && function_exists('is_admin')) {
                    $is_admin = is_admin();
                }
                if ($is_admin) {
                    $this->connected = false;
                    return;
                }
            }

            if ($this->host === '') {
                $this->last_error = 'Cache host is empty.';
                return;
            }

            /*
            Two kinds of sockets allowed:
            1. TCP
            2. UNIX (no port used)
            */
            $is_socket = $this->is_unix_socket($this->host);
            $host = $this->host;
            if ($is_socket && strpos($host, 'unix://') === 0) {
                $host = substr($host, 7);
                // cut prefix:
                // unix:///var/run/redis.sock -> /var/run/redis.sock
            }

            // if unix socket, use port 0
            $port = $is_socket ? 0 : (int) $this->port;
            if ($port <= 0) {
                $port = $this->method === 'memcached' ? 11211 : 6379;
                /**
                 * if port is not valid, we'll use default ones (memcached is 1211) and redis is 6379
                 */
            }

            if ($this->method === 'memcached') {
                $this->connect_memcached($host, $port, $is_socket);
                return;
            }

            $this->connect_redis($host, $port, $is_socket);
        }

        protected function is_admin_context()
        {
            $is_admin = (defined('WP_ADMIN') && WP_ADMIN);
            if (!$is_admin && function_exists('is_admin')) {
                $is_admin = is_admin();
            }
            return (bool) $is_admin;
        }

        /**
         * Admin caching can be disabled while still requiring maintenance operations
         * (flush/delete) to hit the persistent backend and invalidate stale keys.
         */
        protected function ensure_backend_for_admin_maintenance($operation = '')
        {
            if ($this->connected || $this->cache_wp_admin || !$this->is_admin_context()) {
                return;
            }

            $this->connect(true);

            if (!$this->connected) {
                $this->log_debug('admin_maintenance_backend_unavailable', [
                    'operation' => (string) $operation,
                    'method' => $this->method,
                ]);
            }
        }

        protected function connect_redis($host, $port, $is_socket)
        {
            if (!class_exists('Redis')) {
                $this->last_error = 'Redis extension not installed.';
                $this->connected = false;
                $this->redis = null;
                $this->update_backend_health(false, 'redis-extension-missing');
                return;
            }

            $this->connected = false;
            $this->redis = null;

            $max_retries = $this->safe_mode ? 0 : 2;
            $timeout = $this->redis_connect_timeout > 0 ? $this->redis_connect_timeout : 1.0;
            $read_timeout = $this->redis_read_timeout > 0 ? $this->redis_read_timeout : 0.0;
            $persistent_id = $this->build_redis_persistent_id($host, $port, $is_socket);

            // safe mode reffers to simple and predictable.
            for ($attempt = 0; $attempt <= $max_retries; $attempt++) {
                if ($attempt > 0) {
                    $this->log_retry_attempt('connect_redis', $attempt + 1, $max_retries + 1);
                }

                try {
                    $redis = new Redis();
                    $connected = $this->redis_connect_with_timeout(
                        $redis,
                        $this->persistent,
                        $host,
                        $port,
                        $timeout,
                        $persistent_id,
                        $read_timeout
                    );

                    if (!$connected) {
                        throw new RuntimeException('Redis connection failed.');
                    }

                    // from phpredis extensions, it dictates how redis serializes data.
                    if (defined('Redis::OPT_SERIALIZER') && defined('Redis::SERIALIZER_NONE')) {
                        $redis->setOption(Redis::OPT_SERIALIZER, Redis::SERIALIZER_NONE);
                        //  set serialization to none because we already do it
                    }
                    if ($read_timeout > 0 && defined('Redis::OPT_READ_TIMEOUT')) {
                        $redis->setOption(Redis::OPT_READ_TIMEOUT, $read_timeout);
                    }

                    if ($this->password !== '') {
                        $auth_ok = ($this->username !== '')
                            ? $redis->auth([$this->username, $this->password])
                            : $redis->auth($this->password);
                        if (!$auth_ok) {
                            throw new RuntimeException('Redis authentication failed.');
                        }
                    }

                    if ($this->dbid > 0 && !$redis->select($this->dbid)) {
                        throw new RuntimeException('Redis database selection failed.');
                    }

                    if ($this->safe_mode) {
                        $ping = $redis->ping();
                        if ($ping === false) {
                            throw new RuntimeException('Redis ping failed in safe mode.');
                        }
                    } else {
                        if (!$this->validate_redis_ping($redis)) {
                            throw new RuntimeException('Redis ping validation failed.');
                        }
                    }

                    $this->redis = $redis;
                    $this->connected = true;
                    $this->last_error = '';
                    $this->update_backend_health(true, 'redis-connect-success');
                    return;
                } catch (Throwable $e) {
                    $this->last_error = 'Redis error: ' . $e->getMessage();
                    $this->connected = false;
                    $this->redis = null;
                    $this->update_backend_health(false, 'redis-connect-failure');

                    if ($attempt >= $max_retries) {
                        return;
                    }

                    usleep((int) (100000 * ($attempt + 1)));
                }
            }
        }

        protected function connect_memcached($host, $port, $is_socket)
        {
            // Memcached intialization


            // does extension exist?
            if (!class_exists('Memcached')) {
                $this->last_error = 'Memcached extension not installed.';
                $this->connected = false;
                $this->memcached = null;
                $this->update_backend_health(false, 'memcached-extension-missing');
                return;
            }

            $this->connected = false;
            $this->memcached = null;

            try {
                // if persistent cache, save id
                $persistent_id = $this->build_memcached_persistent_id($host, $port, $is_socket);
                $memcached = $this->persistent ? new Memcached($persistent_id) : new Memcached();

                // port (host:port or socket)
                $server_port = $is_socket ? 0 : (int) $port;

                if ($this->safe_mode) {
                    $server_list = $memcached->getServerList();
                    if (!is_array($server_list)) {
                        $server_list = [];
                    }

                    // add servers if it misses
                    //
                    // memcached_server_list_has_expected verifies if the client memcached exists in that server already
                    if (!$this->memcached_server_list_has_expected($server_list, $host, $server_port)) {
                        if (!$memcached->addServer($host, $server_port)) {
                            $this->last_error = 'Memcached addServer failed in safe mode.';
                            $this->connected = false;
                            $this->update_backend_health(false, 'memcached-safe-mode-addserver-failed');
                            return;
                        }
                    }

                    // health check
                    if (!$this->memcached_is_healthy($memcached)) {
                        $this->last_error = 'Memcached server not responding in safe mode.';
                        $this->connected = false;
                        $this->update_backend_health(false, 'memcached-safe-mode-health-failed');
                        return;
                    }
                } else {
                    // SET OPTIONS
                    if (defined('Memcached::OPT_CONNECT_TIMEOUT')) {
                        $memcached->setOption(Memcached::OPT_CONNECT_TIMEOUT, 1000);
                    }
                    if (defined('Memcached::OPT_RETRY_TIMEOUT')) {
                        $memcached->setOption(Memcached::OPT_RETRY_TIMEOUT, 1);
                    }
                    if (defined('Memcached::OPT_SERVER_FAILURE_LIMIT')) {
                        $memcached->setOption(Memcached::OPT_SERVER_FAILURE_LIMIT, 1);
                    }
                    if (defined('Memcached::OPT_REMOVE_FAILED_SERVERS')) {
                        $memcached->setOption(Memcached::OPT_REMOVE_FAILED_SERVERS, true);
                    }
                    // I/O non-blocking. ( inner details for the sever )
                    if (defined('Memcached::OPT_NO_BLOCK')) {
                        $memcached->setOption(Memcached::OPT_NO_BLOCK, true);
                    }
                    // activates Nagle algorithm, for efficiency
                    if (defined('Memcached::OPT_TCP_NODELAY')) {
                        $memcached->setOption(Memcached::OPT_TCP_NODELAY, true);
                    }

                    
                    if ($this->username !== '' || $this->password !== '') {
                        // login via sasl
                        if (method_exists($memcached, 'setSaslAuthData') && defined('Memcached::OPT_BINARY_PROTOCOL')) {
                            $memcached->setOption(Memcached::OPT_BINARY_PROTOCOL, true);
                            $memcached->setSaslAuthData($this->username, $this->password);
                        } else {
                            $this->last_error = 'Memcached SASL auth not supported.';
                            $this->connected = false;
                            $this->update_backend_health(false, 'memcached-sasl-unsupported');
                            return;
                        }
                    }

                    // server_list 
                    $server_list = $memcached->getServerList();
                    if (!is_array($server_list)) {
                        $server_list = [];
                    }

                    // has_expected => the server we want along others
                    // only_expected => only server we want
                    $has_expected_server = $this->memcached_server_list_has_expected($server_list, $host, $server_port);
                    $has_only_expected = $this->memcached_server_list_only_expected($server_list, $host, $server_port);

                    // if list is wrong, we reset server list
                    if (!$has_only_expected && method_exists($memcached, 'resetServerList')) {
                        $memcached->resetServerList();
                        $server_list = [];
                        $has_expected_server = false;
                    }

                    if (!$has_expected_server) {
                        // add our server
                        if (!$memcached->addServer($host, $server_port)) {
                            $this->last_error = 'Memcached addServer failed.';
                            $this->connected = false;
                            $this->update_backend_health(false, 'memcached-addserver-failed');
                            return;
                        }
                    }

                    if (!$this->memcached_is_healthy($memcached)) {
                        $this->last_error = 'Memcached server not responding.';
                        $this->connected = false;
                        $this->update_backend_health(false, 'memcached-health-failed');
                        return;
                    }
                }

                $this->memcached = $memcached;
                $this->connected = true;
                $this->last_error = '';
                $this->update_backend_health(true, 'memcached-connect-success');
            } catch (Throwable $e) {
                $this->last_error = 'Memcached error: ' . $e->getMessage();
                $this->connected = false;
                $this->memcached = null;
                $this->update_backend_health(false, 'memcached-connect-exception');
            }
        }

        // makes sure the connection to external cache is valid and the group is persistent
        protected function should_persist($group)
        {
            return $this->connected && !$this->is_non_persistent_group($group);
        }

        protected function is_non_persistent_group($group)
        {
            $group = $this->sanitize_key_part($group);
            return in_array($group, $this->non_persistent_groups, true);
        }

        protected function normalize_group($group)
        {
            if ($group === '' || $group === null) {
                $group = 'default';
            }
            return $group;
        }

        // create unique key
        protected function build_key($key, $group)
        {
            // create a unique prefix as dicussed above 
            $group = $this->normalize_group($group);
            $san_key = $this->sanitize_key_part($key);
            $san_group = $this->sanitize_key_part($group);

            $prefix = $this->get_group_prefix($san_group);
            $prefix = trim((string) $prefix, '_-:');
            $prefix = $prefix !== '' ? $prefix . ':' : '';

            $base = $this->key_salt . $prefix . $san_group . ':';

            if ($this->method === 'memcached') {
                $version = $this->get_group_version($san_group, $prefix);
                $base .= $version . ':';
            }

            return $base . $san_key;
        }

        // figures out if a group is global (for a multisite) or specific to blog
        protected function get_group_prefix($group)
        {
            return in_array($group, $this->global_groups, true) ? $this->global_prefix : $this->blog_prefix;
        }

        /*
         * Memcached can't eliminate all keys from a group
         * We trick memcached to do that with versioning
         * 
         * Say we set a 
         * options:1:X
         * 
         * Then when we update the version
         * options:2:X 
         * 
         * this will overshadow options1:X 
         * 
         * every group has a version
         */
        protected function build_group_version_key($group, $prefix)
        {
            $prefix = trim((string) $prefix, '_-:');
            $prefix = $prefix !== '' ? $prefix . ':' : '';
            return $this->key_salt . $prefix . '__fp_group_version__:' . $group;
        }


        protected function get_group_version($group, $prefix)
        {
            $prefix = trim((string) $prefix, '_-:');
            $index = $prefix . '|' . $group;

            // if index is found, we return it
            if (isset($this->group_versions[$index])) {
                return (int) $this->group_versions[$index];
            }

            $version = 1;
            if ($this->method === 'memcached' && $this->memcached instanceof Memcached) {
                // if there is a memcached this make sense

                $version_key = $this->build_group_version_key($group, $prefix);
                $stored = $this->memcached->get($version_key); // value for group version
                $result_code = (int) $this->memcached->getResultCode(); // was the last operation succesfull?
                // try to find key from the stored

                if ($result_code === Memcached::RES_SUCCESS) {
                    $version = max(1, (int) $stored); // we found, store it
                } elseif ($this->is_memcached_not_found($result_code)) {
                    $added = $this->memcached->add($version_key, 1, 0); // add a new key with 1 and try to read again
                    if (!$added) {
                        $stored = $this->memcached->get($version_key);
                        if ((int) $this->memcached->getResultCode() === Memcached::RES_SUCCESS) {
                            $version = max(1, (int) $stored); // version is set
                        }
                    }
                } else {
                    $this->last_error = 'Memcached group version read failed with code ' . $result_code . '.';
                }
            }

            // save version
            $this->group_versions[$index] = $version;
            return $version;
        }

        protected function bump_group_version($group)
        {
            // create group versioning, to help memcached
            // 
            // !!! EDGE CASE 
            // If key gets eliminated from internal cache, the version is reset
            // if the version is reset, older items may still exist.
            //
            $prefix = $this->get_group_prefix($group);
            $prefix = trim((string) $prefix, '_-:');
            $index = $prefix . '|' . $group;
            $version_key = $this->build_group_version_key($group, $prefix);

            $new_version = 1;
            if ($this->memcached instanceof Memcached) {
                //increment current version so we skip the old ones
                $new_version = $this->memcached->increment($version_key, 1);
                if ($new_version === false) {
                    $result_code = (int) $this->memcached->getResultCode(); // incrementing failed, we set manually
                    if ($this->is_memcached_not_found($result_code)) {
                        $added = $this->memcached->add($version_key, 2, 0);
                        if ($added) {
                            $new_version = 2; // create that version
                        } else {
                            $new_version = $this->memcached->increment($version_key, 1); // new_version 
                        }
                    } else {
                        $this->last_error = 'Memcached group version increment failed with code ' . $result_code . '.';
                        return false;
                    }
                }

                if ($new_version === false) {
                    return false;
                }
            } else {
                $new_version = ($this->group_versions[$index] ?? 1) + 1;
            }

            $this->group_versions[$index] = (int) $new_version;
            return true;
        }

        // delete a group from runtime (or local cache)
        protected function flush_runtime_group($group)
        {
            // detect with a needle if that key is part of a group, unset it if so.
            $needle = ':' . $this->sanitize_key_part($group) . ':';
            foreach ($this->cache as $key => $value) {
                if (strpos($key, $needle) !== false) {
                    unset($this->cache[$key]);
                }
            }
        }

        // only used for persistent backend
        protected function key_exists($derived_key)
        {
            if ($this->method === 'memcached' && $this->memcached instanceof Memcached) {
                $this->memcached->get($derived_key);
                $result_code = (int) $this->memcached->getResultCode();
                if ($result_code === Memcached::RES_SUCCESS) {
                    return true;
                }
                if ($this->is_memcached_not_found($result_code)) {
                    return false;
                }
                $this->last_error = 'Memcached key_exists failed with code ' . $result_code . '.';
                return false;
            }
            if ($this->redis instanceof Redis) {
                return (bool) $this->redis->exists($derived_key);
            }
            return false;
        }

        /**
         * 
         * Persist here means external cache,
         * don't confuse with persistent connection
         * 
         */
        protected function persist_get($derived_key)
        {
            // poll if SAFE_MODE is disabled
            //
            // keep in mind safe mode is meant to make things simpler and avoid complex bugs

            if ($this->method === 'memcached') {
                $max_attempts = $this->safe_mode ? 1 : 2;
                for ($attempt = 0; $attempt < $max_attempts; $attempt++) {
                    if ($attempt > 0) {
                        $this->log_retry_attempt('persist_get_memcached', $attempt + 1, $max_attempts);
                    }

                    // try to reconnect backend
                    if (!$this->connected || !($this->memcached instanceof Memcached)) {
                        if ($this->safe_mode || !$this->reconnect_backend('persist_get_memcached')) {
                            break;
                        }
                    }

                    // Safely extract element
                    try {
                        $value = $this->memcached->get($derived_key);
                        $result_code = (int) $this->memcached->getResultCode();
                        if ($result_code === Memcached::RES_SUCCESS) {
                            return $value; // found value
                        }
                        // if it is not found it returns null
                        if ($this->is_memcached_not_found($result_code)) {
                            return null;
                        }
                        // beware, if memcached has other kind of errors, we continue with the next attempt
                        $this->last_error = 'Memcached get failed with code ' . $result_code . '.';
                    } catch (Throwable $e) {
                        $this->last_error = 'Memcached get error: ' . $e->getMessage();
                    }

                    $this->connected = false;
                    $this->memcached = null;
                    $this->update_backend_health(false, 'persist-get-memcached-failure');
                }

                return $this->transient_fallback_get_from_derived_key($derived_key); // fallback for transient
            }

            if ($this->method === 'redis') {
                $max_attempts = $this->safe_mode ? 1 : 2;
                // similar to memcached

                for ($attempt = 0; $attempt < $max_attempts; $attempt++) {
                    if ($attempt > 0) {
                        $this->log_retry_attempt('persist_get_redis', $attempt + 1, $max_attempts);
                    }
                    
                    // break out to fallback
                    if (!$this->connected || !($this->redis instanceof Redis)) {
                        if ($this->safe_mode || !$this->reconnect_backend('persist_get_redis')) {
                            break;
                        }
                    }

                    try {
                        $value = $this->redis->get($derived_key);
                        if ($value === false || $value === null) {
                            if ($value === false && (int) $this->redis->exists($derived_key) > 0) {
                                return false; // key exists
                            }
                            return null; // doesn't exist
                        }
                        return $value; // found
                    } catch (Throwable $e) {
                        $this->last_error = 'Redis get error: ' . $e->getMessage();
                    }

                    $this->connected = false;
                    $this->redis = null;
                    $this->update_backend_health(false, 'persist-get-redis-failure');
                }

                return $this->transient_fallback_get_from_derived_key($derived_key); // transient fallback
            }

            return $this->transient_fallback_get_from_derived_key($derived_key); // transient fallback
        }

        protected function persist_add($derived_key, $value, $expiration)
        {
            // see persist_get for comments
            $payload = $this->maybe_serialize($value);

            if ($this->method === 'memcached') {
                $max_attempts = $this->safe_mode ? 1 : 2; // safe mode leads to more predictable results

                for ($attempt = 0; $attempt < $max_attempts; $attempt++) {
                    if ($attempt > 0) {
                        $this->log_retry_attempt('persist_add_memcached', $attempt + 1, $max_attempts);
                    }

                    if (!$this->connected || !($this->memcached instanceof Memcached)) {
                        if ($this->safe_mode || !$this->reconnect_backend('persist_add_memcached')) {
                            break; // go to fallback
                        }
                    }

                    try {
                        $result = $this->memcached->add($derived_key, $payload, $expiration);
                        if ($result) {
                            return true; // try to add
                        }

                        $result_code = (int) $this->memcached->getResultCode();
                        if ($result_code === Memcached::RES_NOTSTORED || $result_code === Memcached::RES_DATA_EXISTS) {
                            return false; // exist already
                        }

                        $this->last_error = 'Memcached add failed with code ' . $result_code . '.';
                    } catch (Throwable $e) {
                        $this->last_error = 'Memcached add error: ' . $e->getMessage();
                    }

                    $this->connected = false;
                    $this->memcached = null;
                    $this->update_backend_health(false, 'persist-add-memcached-failure');
                }

                return $this->transient_fallback_add_from_derived_key($derived_key, $value, $expiration);
            }

            if ($this->method === 'redis') {
                $max_attempts = $this->safe_mode ? 1 : 2;
                for ($attempt = 0; $attempt < $max_attempts; $attempt++) {
                    if ($attempt > 0) {
                        $this->log_retry_attempt('persist_add_redis', $attempt + 1, $max_attempts);
                    }

                    if (!$this->connected || !($this->redis instanceof Redis)) {
                        if ($this->safe_mode || !$this->reconnect_backend('persist_add_redis')) {
                            break;
                        }
                    }

                    try {
                        // if safe mode, we'll use a basic add, otherwise a options based 
                        $result = $this->safe_mode
                            ? $this->redis_add_basic($derived_key, $payload, $expiration)
                            : $this->redis_set_with_options($derived_key, $payload, $expiration, true);
                        if ($result) {
                            return true;
                        }

                        if ($this->validate_redis_ping($this->redis)) {
                            return false; // false, ping test went good
                        }

                        $this->last_error = 'Redis add failed because connection dropped.';
                    } catch (Throwable $e) {
                        $this->last_error = 'Redis add error: ' . $e->getMessage();
                    }

                    $this->connected = false;
                    $this->redis = null;
                    $this->update_backend_health(false, 'persist-add-redis-failure');
                }

                return $this->transient_fallback_add_from_derived_key($derived_key, $value, $expiration); // fallback
            }

            return $this->transient_fallback_add_from_derived_key($derived_key, $value, $expiration); // fallback
        }

        protected function persist_set($derived_key, $value, $expiration)
        {
            // attempts to add a value to a persistent external cache
            $payload = $this->maybe_serialize($value); // serialize

            if ($this->method === 'memcached') {
                // start attempt polling
                $max_attempts = $this->safe_mode ? 1 : 2; // safe mode allows for more predictable results
                for ($attempt = 0; $attempt < $max_attempts; $attempt++) {
                    if ($attempt > 0) {
                        $this->log_retry_attempt('persist_set_memcached', $attempt + 1, $max_attempts);
                    }

                    if (!$this->connected || !($this->memcached instanceof Memcached)) {
                        if ($this->safe_mode || !$this->reconnect_backend('persist_set_memcached')) {
                            break; // prepare for fallback
                        }
                    }

                    try {
                        $result = $this->memcached->set($derived_key, $payload, $expiration);
                        if ($result) {
                            return true; //  set
                        }

                        $result_code = (int) $this->memcached->getResultCode();
                        $this->last_error = 'Memcached set failed with code ' . $result_code . '.';
                    } catch (Throwable $e) {
                        $this->last_error = 'Memcached set error: ' . $e->getMessage();
                    }

                    $this->connected = false;
                    $this->memcached = null;
                    $this->update_backend_health(false, 'persist-set-memcached-failure');
                }

                return $this->transient_fallback_set_from_derived_key($derived_key, $value, $expiration);
            }

            if ($this->method === 'redis') {
                $max_attempts = $this->safe_mode ? 1 : 2; // safe mode allows for more predictable results
                for ($attempt = 0; $attempt < $max_attempts; $attempt++) {
                    if ($attempt > 0) {
                        $this->log_retry_attempt('persist_set_redis', $attempt + 1, $max_attempts);
                    }

                    if (!$this->connected || !($this->redis instanceof Redis)) {
                        if ($this->safe_mode || !$this->reconnect_backend('persist_set_redis')) {
                            break; // prepare for fallback
                        }
                    }

                    try {
                        $result = $this->safe_mode
                            ? $this->redis_set_basic($derived_key, $payload, $expiration)
                            : $this->redis_set_with_options($derived_key, $payload, $expiration, false);
                        if ($result) {
                            return true;
                        }

                        if ($this->validate_redis_ping($this->redis)) { // can connect to redis
                            return false;
                        }

                        $this->last_error = 'Redis set failed because connection dropped.';
                    } catch (Throwable $e) {
                        $this->last_error = 'Redis set error: ' . $e->getMessage();
                    }

                    $this->connected = false;
                    $this->redis = null;
                    $this->update_backend_health(false, 'persist-set-redis-failure');
                }

                return $this->transient_fallback_set_from_derived_key($derived_key, $value, $expiration);
            }

            return $this->transient_fallback_set_from_derived_key($derived_key, $value, $expiration);
        }

        protected function persist_delete($derived_key)
        {
            if ($this->method === 'memcached') {
                if (!$this->connected || !($this->memcached instanceof Memcached)) {
                    if ($this->safe_mode || !$this->reconnect_backend('persist_delete_memcached')) {
                        return $this->transient_fallback_delete_from_derived_key($derived_key);
                    }
                }

                $result = $this->memcached->delete($derived_key);
                if ($result) {
                    return true;
                }

                $result_code = (int) $this->memcached->getResultCode();
                if ($this->is_memcached_not_found($result_code)) {
                    return true;
                }

                $this->last_error = 'Memcached delete failed with code ' . $result_code . '.';
                $this->update_backend_health(false, 'persist-delete-memcached-failure');
                return $this->transient_fallback_delete_from_derived_key($derived_key);
            }

            if ($this->method === 'redis') {
                if (!$this->connected || !($this->redis instanceof Redis)) {
                    if ($this->safe_mode || !$this->reconnect_backend('persist_delete_redis')) {
                        return $this->transient_fallback_delete_from_derived_key($derived_key);
                    }
                }

                try {
                    return (bool) $this->redis->del($derived_key);
                } catch (Throwable $e) {
                    $this->last_error = 'Redis delete error: ' . $e->getMessage();
                    $this->connected = false;
                    $this->redis = null;
                    $this->update_backend_health(false, 'persist-delete-redis-failure');
                    if (!$this->safe_mode && $this->reconnect_backend('persist_delete_redis_retry')) {
                        try {
                            return (bool) $this->redis->del($derived_key);
                        } catch (Throwable $retry_exception) {
                            $this->last_error = 'Redis delete retry error: ' . $retry_exception->getMessage();
                        }
                    }
                }

                return $this->transient_fallback_delete_from_derived_key($derived_key);
            }

            return $this->transient_fallback_delete_from_derived_key($derived_key);
        }

        protected function persist_flush()
        {
            $this->log_debug('flush_operation', ['target' => 'all', 'method' => $this->method]);

            if ($this->method === 'memcached') {
                if (!$this->connected || !($this->memcached instanceof Memcached)) {
                    if ($this->safe_mode || !$this->reconnect_backend('persist_flush_memcached')) {
                        return false;
                    }
                }

                $flushed = (bool) $this->memcached->flush();
                if ($flushed) {
                    return true;
                }

                $result_code = (int) $this->memcached->getResultCode();
                if ($result_code === Memcached::RES_SUCCESS) {
                    return true;
                }
                $this->last_error = 'Memcached flush failed with code ' . $result_code . '.';
                $this->update_backend_health(false, 'flush-memcached-failure');
                return false;
            }

            if ($this->method === 'redis') {
                if (!$this->connected || !($this->redis instanceof Redis)) {
                    if ($this->safe_mode || !$this->reconnect_backend('persist_flush_redis')) {
                        return false;
                    }
                }

                $pattern = $this->key_salt !== '' ? $this->key_salt . '*' : '';
                if ($pattern === '') {
                    if (!$this->allow_unsafe_flushdb) {
                        $this->last_error = 'Unsafe Redis FLUSHDB blocked because key_salt is empty.';
                        $this->log_debug('flush_operation', ['target' => 'db', 'result' => 'blocked-empty-salt']);
                        return false;
                    }

                    try {
                        return (bool) $this->redis->flushdb();
                    } catch (Throwable $e) {
                        $this->last_error = 'Redis flushdb error: ' . $e->getMessage();
                        $this->update_backend_health(false, 'flush-redis-flushdb-failure');
                        return false;
                    }
                }

                return $this->redis_scan_delete_pattern($pattern);
            }

            return false;
        }

        protected function persist_flush_group_redis($group)
        {
            if (!($this->redis instanceof Redis)) {
                return false;
            }

            $group = $this->sanitize_key_part($this->normalize_group($group));
            $prefix = $this->get_group_prefix($group);
            $prefix = trim((string) $prefix, '_-:');
            $prefix = $prefix !== '' ? $prefix . ':' : '';
            $pattern = $this->key_salt . $prefix . $group . ':*';
            $this->log_debug('flush_operation', ['target' => 'group', 'group' => $group, 'pattern' => $pattern]);
            return $this->redis_scan_delete_pattern($pattern);
        }

        protected function persist_incr($derived_key, $offset)
        {
            if ($this->method === 'memcached' && $this->memcached instanceof Memcached) {
                $value = $this->memcached->increment($derived_key, $offset);
                if ($value === false && $this->memcached->getResultCode() !== Memcached::RES_SUCCESS) {
                    return false;
                }
                return $value;
            }
            if ($this->redis instanceof Redis) {
                return $this->redis->incrBy($derived_key, $offset);
            }
            return false;
        }

        protected function persist_decr($derived_key, $offset)
        {
            if ($this->method === 'memcached' && $this->memcached instanceof Memcached) {
                $value = $this->memcached->decrement($derived_key, $offset);
                if ($value === false && $this->memcached->getResultCode() !== Memcached::RES_SUCCESS) {
                    return false;
                }
                return $value;
            }
            if ($this->redis instanceof Redis) {
                return $this->redis->decrBy($derived_key, $offset);
            }
            return false;
        }
        protected function is_cache_addition_suspended()
        {
            return function_exists('wp_suspend_cache_addition') && wp_suspend_cache_addition();
        }

        protected function normalize_expiration($expiration)
        {
            $expiration = (int) $expiration;

            if ($expiration < 0) {
                $expiration = 0;
            }

            if ($expiration === 0 && $this->default_ttl > 0) {
                $expiration = (int) $this->default_ttl; // set to default
            }

            if ($expiration < 0) {
                $expiration = 0; // another sanity check
            }

            if ($this->method === 'memcached' && $expiration > 2592000) {
                $now = time(); 
                if ($expiration <= $now) {
                    $expiration = $now + $expiration;
                }
            }

            return $expiration;
        }

        protected function is_unix_socket($host)
        {
            return is_string($host) && ($host !== '') && (strpos($host, '/') === 0 || strpos($host, 'unix://') === 0);
        }

        protected function maybe_serialize($data)
        {
            if (is_array($data) || is_object($data)) {
                return serialize($data);
            }

            if (!is_scalar($data) && $data !== null) {
                return serialize($data);
            }

            if (is_string($data) && $this->is_serialized($data, false)) {
                return $data;
            }

            return $data;
        }

        protected function maybe_unserialize($data)
        {
            if ($this->is_serialized($data)) {
                $value = @unserialize($data);
                return is_object($value) ? clone $value : $value;
            }
            return $data;
        }

        protected function is_serialized($data, $strict = true)
        {
            if (!is_string($data)) {
                return false;
            }

            $data = trim($data);
            if ($data === 'N;') {
                return true;
            }

            if (strlen($data) < 4) {
                return false;
            }

            if ($data[1] !== ':') {
                return false;
            }

            if ($strict) {
                $lastc = substr($data, -1);
                if ($lastc !== ';' && $lastc !== '}') {
                    return false;
                }
            } else {
                $semicolon = strpos($data, ';');
                $brace = strpos($data, '}');
                if ($semicolon === false && $brace === false) {
                    return false;
                }
                if ($semicolon !== false && $semicolon < 3) {
                    return false;
                }
                if ($brace !== false && $brace < 4) {
                    return false;
                }
            }

            $token = $data[0];
            switch ($token) {
                case 's':
                    if ($strict && substr($data, -2, 1) !== '"') {
                        return false;
                    } elseif (!$strict && strpos($data, '"') === false) {
                        return false;
                    }
                    return (bool) preg_match('/^s:[0-9]+:\".*\";$/s', $data);
                case 'a':
                case 'O':
                case 'E':
                case 'C':
                    return (bool) preg_match("/^{$token}:[0-9]+:/s", $data);
                case 'b':
                case 'i':
                case 'd':
                    $end = $strict ? '$' : '';
                    return (bool) preg_match("/^{$token}:[0-9.E+-]+;$end/", $data);
                case 'R':
                case 'r':
                    return (bool) preg_match("/^{$token}:[0-9]+;$/", $data);
            }

            return false;
        }

        protected function build_redis_persistent_id($host, $port, $is_socket)
        {
            $target = $is_socket ? 'socket:' . $host : ((string) $host . ':' . (int) $port);
            return 'fastpixel-redis:' . md5($target . '|' . (string) $this->dbid . '|' . $this->username);
        }

        //  connect to redis
        protected function redis_connect_with_timeout(Redis $redis, $persistent, $host, $port, $timeout, $persistent_id, $read_timeout)
        {
            /*
             *  pconnect parameters for refrence
             *  host
             *  port
             *  timeout
             *  persistent_id - can be a constant string
             *  retry_interval (ms) = 0.0
             *  redis_timeout (s) 
             *
             *  see phpredis api docs for more info
             *
             *
             *  what's the difference between timeout and read_timeout?
             *
             *  timeout - how much you wait to connect to redis initially (small, needs to fail fast, somewhere under 0.5-2s)
             *  read_timeout - how much you wait for a response after connection (a little big bigger 0.5-3s)
             *  retry_interval - the added pause before attempting reconnection (we just default to 0)
             * */
            $timeout = (float) $timeout;
            $read_timeout = (float) $read_timeout;

            if ($this->safe_mode) {
                if ($persistent) {
                    return (bool) $redis->pconnect($host, $port, $timeout, $persistent_id); // persistent connect if an id
                }
                return (bool) $redis->connect($host, $port, $timeout); // basic connection
            }

            if ($persistent) { // persistent connect with timeout
                if ($read_timeout > 0) {
                    // Attention ! not on all versions you can set a read_timeout, redis version may have 4 params so we will fallback in case
                    try {
                        return (bool) $redis->pconnect($host, $port, $timeout, $persistent_id, 0, $read_timeout);
                    } catch (ArgumentCountError $e) {
                    }
                }
                return (bool) $redis->pconnect($host, $port, $timeout, $persistent_id); // pconnect without timeout
            }

            if ($read_timeout > 0) {
                try {
                    return (bool) $redis->connect($host, $port, $timeout, '', 0, $read_timeout); // no persistent id, use timeout. Fallback for redis verison.
                } catch (ArgumentCountError $e) {
                }
            }

            return (bool) $redis->connect($host, $port, $timeout); // basic connection, no persistent
        }

        protected function validate_redis_ping(Redis $redis)
        {
            if ($this->safe_mode) {
                try {
                    return $redis->ping() !== false; // safe fallback
                } catch (Throwable $e) {
                    return false;
                }
            }

            // initialize two control variables
            $should_restore = false;
            $previous_reply_literal = null;

            // REDIS OPT REPLY LITERAL allows to receive a PONG response (see below)
            // the output of ping will be 'literarly' (string) if this option is enabled
            // we risk boolean response if we don't set OPT_REPLY_LITERAL ( see on phpredis.github.io more info)
            if (defined('Redis::OPT_REPLY_LITERAL') && method_exists($redis, 'getOption') && method_exists($redis, 'setOption')) {
                try {
                    // read the previous reply literal option
                    $previous_reply_literal = $redis->getOption(Redis::OPT_REPLY_LITERAL);
                    // if option was disabled, we enableit temporary (with should_restore)
                    if ((is_bool($previous_reply_literal) || is_int($previous_reply_literal)) && !$previous_reply_literal) { 
                        $redis->setOption(Redis::OPT_REPLY_LITERAL, true);
                        $should_restore = true;
                    }
                } catch (Throwable $e) {
                    $should_restore = false;
                }
            }

            /*
             * PING/PONG is a heartbeat conceptually.
             * PONG in redis is the response to ping
             *
             *
             * */

            try {
                $pong = $redis->ping(); // ping gets pong
            } catch (Throwable $e) {
                $pong = false;
            }

            if ($should_restore) {
                try {
                    // if changed, set back
                    $redis->setOption(Redis::OPT_REPLY_LITERAL, (bool) $previous_reply_literal);
                } catch (Throwable $e) {
                }
            }

            // Different phpredis versions can return true, "PONG" or "+PONG".
            if ($pong === true) {
                return true;
            }

            if (is_string($pong)) {
                $pong = strtoupper(trim($pong));
                return $pong === 'PONG' || $pong === '+PONG';
            }

            return false;
        }

        /* Main redis setting strategy, less predictable  */
        protected function redis_set_with_options($key, $payload, $expiration, $nx = false)
        {
            if (!($this->redis instanceof Redis)) {
                return false;
            }

            $expiration = (int) $expiration;
            $options = [];
            if ($nx) {
                $options[0] = 'nx'; // nx has a 'add' like nature, only sets key if it dosen't exist
                // nx allows for 'atomic' add operations in Redis
            }
            if ($expiration > 0) {
                $options['ex'] = $expiration; // expiration option
            }

            $result = empty($options)
                ? $this->redis->set($key, $payload)
                : $this->redis->set($key, $payload, $options);

            return $result === true || $result === 'OK'; // returns OK
        }

        /* basic red set, no nx, utilized by safe mode */
        /* the second redis set strategy (very predictable) */
        protected function redis_set_basic($key, $payload, $expiration)
        {
            if (!($this->redis instanceof Redis)) {
                return false;
            }

            $expiration = (int) $expiration;
            if ($expiration > 0) {
                $result = $this->redis->setex($key, $expiration, $payload); // set the key with an expriation
                return $result === true || $result === 'OK';
            }

            $result = $this->redis->set($key, $payload);
            return $result === true || $result === 'OK';
        }

        protected function redis_add_basic($key, $payload, $expiration)
        {
            if (!($this->redis instanceof Redis)) {
                return false;
            }

            $expiration = (int) $expiration;
            $added = (bool) $this->redis->setnx($key, $payload);
            if ($added && $expiration > 0) {
                $this->redis->expire($key, $expiration);
            }

            return $added;
        }

        protected function redis_scan_delete_pattern($pattern)
        {
            // safely delete many keys in an efficient manner
            if (!($this->redis instanceof Redis)) {
                return false;
            }

            $prefix = rtrim((string) $pattern, '*');
            $iterator = null;
            $stalled = 0;
            $max_loops = 100000;

            for ($loop = 0; $loop < $max_loops; $loop++) { // loop over this to scan many times
                $previous_iterator = $iterator;

                try {
                    // Scan the DB and filter by prefix in PHP. This mirrors the direct admin purge path
                    // and avoids MATCH-specific cursor quirks seen on some phpredis/server combinations.
                    $keys = $this->redis->scan($iterator); // iterator is updated via reference
                } catch (Throwable $e) {
                    $this->last_error = 'Redis SCAN failed: ' . $e->getMessage();
                    return false;
                }

                // if we scanned keys, we delete them
                if (is_array($keys) && !empty($keys)) {
                    $matched_keys = [];
                    foreach ($keys as $key) {
                        if (!is_string($key)) {
                            continue;
                        }
                        if ($prefix === '' || strpos($key, $prefix) === 0) {
                            $matched_keys[] = $key;
                        }
                    }
                    if (!empty($matched_keys)) {
                        $this->redis_delete_keys_with_pipeline($matched_keys); // batch delete keys
                    }
                }

                if ($iterator === 0 || $iterator === '0' || $iterator === null || $iterator === false) {
                    return true; // scan done
                }

                if ($iterator === $previous_iterator) {
                    $stalled++;
                    if ($stalled >= 3) { // prevent stalling
                        $this->last_error = 'Redis SCAN cursor stalled.';
                        return false;
                    }
                } else {
                    $stalled = 0; // reset counter
                }
            }

            $this->last_error = 'Redis SCAN loop guard reached.';
            return false;
        }

        protected function redis_delete_keys_with_pipeline(array $keys)
        {
            // efficiently deletes many keys in redis 
            if (!($this->redis instanceof Redis) || empty($keys)) {
                return;
            }

            $keys = array_values(array_filter($keys, 'is_string'));
            if (empty($keys)) {
                return;
            }

            foreach (array_chunk($keys, 250) as $chunk) { // 250 is max batch dimension (there is no limit to my knowledge but this prevents risks)
                try {
                    if (!$this->safe_mode && defined('Redis::PIPELINE')) {
                        $pipeline = $this->redis->multi(Redis::PIPELINE); // create pipeline
                        if ($pipeline instanceof Redis) {
                            foreach ($chunk as $key) {
                                $pipeline->del($key); // we scedule deletion
                            }
                            $pipeline->exec(); // we delete keys
                            continue;
                        }
                    }
 
                    $this->redis->del($chunk); // optional fallback
                } catch (Throwable $e) {
                    $this->last_error = 'Redis pipeline delete failed: ' . $e->getMessage();
                    try {
                        $this->redis->del($chunk); // fallback
                    } catch (Throwable $ignored) {
                    }
                }
            }
        }

        protected function build_memcached_persistent_id($host, $port, $is_socket)
        {
            $target = $is_socket ? 'socket:' . $host : ((string) $host . ':' . (int) $port);
            return 'fastpixel-memcached:' . md5($target . '|' . $this->username);
        }

        protected function memcached_server_list_has_expected(array $server_list, $host, $port)
        {
            // see usage when creating memcached
            foreach ($server_list as $server) {
                if (!is_array($server)) {
                    continue;
                }

                $server_host = isset($server['host']) ? (string) $server['host'] : '';
                $server_port = isset($server['port']) ? (int) $server['port'] : 0;
                if ($server_host === (string) $host && $server_port === (int) $port) {
                    return true;
                }
            }

            return false;
        }

        protected function memcached_server_list_only_expected(array $server_list, $host, $port)
        {
            // see usage when creating memcached
            if (empty($server_list)) {
                return true;
            }

            foreach ($server_list as $server) {
                if (!is_array($server)) {
                    return false;
                }

                $server_host = isset($server['host']) ? (string) $server['host'] : '';
                $server_port = isset($server['port']) ? (int) $server['port'] : 0;
                if ($server_host !== (string) $host || $server_port !== (int) $port) {
                    return false;
                }
            }

            return true;
        }

        protected function memcached_is_healthy(Memcached $memcached)
        {
            try {
                $versions = $memcached->getVersion();
            } catch (Throwable $e) {
                return false;
            }

            if (empty($versions) || !is_array($versions)) {
                return false;
            }

            foreach ($versions as $version) {
                if (is_string($version) && $version !== '' && $version !== '255.255.255') { // '' and 255.255.255 are not responsible
                    return true;
                }
            }

            return false;
        }

        protected function is_memcached_not_found($result_code)
        {
            return (int) $result_code === Memcached::RES_NOTFOUND;
        }

        // optional reason for explicit speaking
        protected function reconnect_backend($reason = 'generic')
        {
            if ($this->safe_mode) {
                $this->log_debug('reconnect_skipped_safe_mode', ['reason' => (string) $reason, 'method' => $this->method]);
                return false;
            }

            $this->log_reconnect_attempt((string) $reason);
            $this->connected = false;
            $this->redis = null;
            $this->memcached = null;
            $this->connect();
            $this->update_backend_health($this->connected, 'reconnect:' . (string) $reason);
            $this->log_debug('reconnect_result', ['reason' => (string) $reason, 'connected' => $this->connected ? 1 : 0, 'method' => $this->method]);
            return $this->connected;
        }

        protected function log_debug($event, array $context = [])
        {
            if (!$this->debug_enabled) {
                return;
            }

            $message = '[FastPixel Object Cache] ' . (string) $event;
            if (!empty($context)) {
                $encoded = json_encode($context, JSON_UNESCAPED_SLASHES);
                if (is_string($encoded)) {
                    $message .= ' ' . $encoded;
                }
            }

            error_log($message);
        }

        protected function log_retry_attempt($operation, $attempt_number, $max_attempts)
        {
            $this->log_debug('retry_attempt', [
                'operation' => (string) $operation,
                'attempt' => (int) $attempt_number,
                'max' => (int) $max_attempts,
            ]);
        }

        protected function log_reconnect_attempt($reason)
        {
            $this->log_debug('reconnect_attempt', [
                'reason' => (string) $reason,
                'method' => $this->method,
            ]);
        }

        protected function update_backend_health($healthy, $source = '')
        {
            $new_status = $healthy ? 'up' : 'down';
            // if status is the same
            if ($this->last_backend_health === $new_status) {
                return;
            }

            $this->last_backend_health = $new_status;
            $this->log_debug('backend_health_change', [
                'status' => $new_status,
                'source' => (string) $source,
                'method' => $this->method,
            ]);
        }

        protected function can_use_transient_db_fallback($group)
        {
            // if we store transients and the object is a transient
            return $this->store_transients && $this->_is_transients_group($this->normalize_group($group));
        }

        protected function normalize_transient_expiration($expiration)
        {
            $expiration = (int) $expiration;
            if ($expiration < 0) {
                return 0; // no negative time
            }

            // expriation relative to time
            // for memcacehd and TTL > 30 days, the timestamp may become absolute
            if ($this->method === 'memcached' && $expiration > 2592000) {
                $now = time();
                if ($expiration > $now) {
                    $expiration = max(1, $expiration - $now);
                }
            }

            return $expiration;
        }

        protected function extract_transient_fallback_context($derived_key)
        {
            // finds if a key is a transient in a nutshell based on a few scenarios
            if (!$this->store_transients || !is_string($derived_key) || $derived_key === '') {
                return null;
            }

            $parts = explode(':', $derived_key);
            $count = count($parts);
            if ($count < 2) {
                return null; // something wrong
            }

            $transient_key = $parts[$count - 1];
            $group = $parts[$count - 2];
            if ($this->_is_transients_group($group)) {
                return ['group' => $group, 'key' => $transient_key];
            }

            if ($count >= 3 && ctype_digit((string) $parts[$count - 2])) {
                $group = $parts[$count - 3];
                if ($this->_is_transients_group($group)) {
                    return ['group' => $group, 'key' => $transient_key];
                }
            }

            return null;
        }

        protected function transient_fallback_get_from_derived_key($derived_key)
        {
            $context = $this->extract_transient_fallback_context($derived_key);
            if (!is_array($context)) {
                return null;
            }

            $this->log_debug('fallback_to_db_transient', [
                'operation' => 'get',
                'group' => $context['group'],
                'key' => $context['key'],
            ]);
            $value = $this->_transient_get($context['key'], $context['group']);
            return $value === false ? null : $value;
        }

        protected function transient_fallback_set_from_derived_key($derived_key, $value, $expiration)
        {
            $context = $this->extract_transient_fallback_context($derived_key);
            if (!is_array($context)) {
                return false;
            }

            $this->log_debug('fallback_to_db_transient', [
                'operation' => 'set',
                'group' => $context['group'],
                'key' => $context['key'],
            ]);
            $expiration = $this->normalize_transient_expiration($expiration);
            return (bool) $this->_transient_set($context['key'], $value, $context['group'], $expiration);
        }

        protected function transient_fallback_add_from_derived_key($derived_key, $value, $expiration)
        {
            $context = $this->extract_transient_fallback_context($derived_key);
            if (!is_array($context)) {
                return false;
            }

            $this->log_debug('fallback_to_db_transient', [
                'operation' => 'add',
                'group' => $context['group'],
                'key' => $context['key'],
            ]);
            if ($this->_transient_get($context['key'], $context['group']) !== false) {
                return false;
            }

            $expiration = $this->normalize_transient_expiration($expiration);
            return (bool) $this->_transient_set($context['key'], $value, $context['group'], $expiration);
        }

        protected function transient_fallback_delete_from_derived_key($derived_key)
        {
            $context = $this->extract_transient_fallback_context($derived_key);
            if (!is_array($context)) {
                return false;
            }

            $this->log_debug('fallback_to_db_transient', [
                'operation' => 'delete',
                'group' => $context['group'],
                'key' => $context['key'],
            ]);
            $this->_transient_del($context['key'], $context['group']);
            return true;
        }

        protected function add_to_internal_cache($derived_key, $value)
        {
            if (is_object($value)) {
                $this->cache[$derived_key] = clone $value;
                return;
            }
            $this->cache[$derived_key] = $value;
        }

	/**
	 * Get `Store Transients` setting value.
	 *
	 *
	 * @param string $group Group name.
	 * @return bool
	 */
	public function store_transients( $group ) {
		return $this->can_use_transient_db_fallback( $group );
	}

	/**
	 * Check if the group belongs to transients or not.
	 *
	 *
	 * @param string $group Group name.
	 * @return bool
	 */
	private function _is_transients_group( $group ) {
		$group = $this->sanitize_key_part( $this->normalize_group( $group ) );
		return in_array( $group, [ 'transient', 'site-transient' ], true );
	}


	/**
	 * Get transient from wp table
	 *
	 * Retrieves transient data from WordPress options table.
	 *
	 * @param string $transient Transient name.
	 * @param string $group     Transient group ('transient' or 'site-transient').
	 * @return mixed Transient value or false if not found.
	 */
	private function _transient_get( $transient, $group ) {
		if ( 'transient' === $group ) {
			/****  WP func start */
			$transient_option = '_transient_' . $transient;
			if ( ! wp_installing() ) {
				// If option is not in alloptions, it is not autoloaded and thus has a timeout
				$alloptions = wp_load_alloptions();
				if ( ! isset( $alloptions[ $transient_option ] ) ) {
					$transient_timeout = '_transient_timeout_' . $transient;
					$timeout           = get_option( $transient_timeout );
					if ( false !== $timeout && $timeout < time() ) {
						delete_option( $transient_option );
						delete_option( $transient_timeout );
						$value = false;
					}
				}
			}

			if ( ! isset( $value ) ) {
				$value = get_option( $transient_option );
			}
			/**** WP func end */
		} elseif ( 'site-transient' === $group ) {
			/**** WP func start */
			$no_timeout       = [ 'update_core', 'update_plugins', 'update_themes' ];
			$transient_option = '_site_transient_' . $transient;
			if ( ! in_array( $transient, $no_timeout, true ) ) {
				$transient_timeout = '_site_transient_timeout_' . $transient;
				$timeout           = get_site_option( $transient_timeout );
				if ( false !== $timeout && $timeout < time() ) {
					delete_site_option( $transient_option );
					delete_site_option( $transient_timeout );
					$value = false;
				}
			}

			if ( ! isset( $value ) ) {
				$value = get_site_option( $transient_option );
			}
			/**** WP func end */
		} else {
			$value = false;
		}

		return $value;
	}

	/**
	 * Set transient to WP table
	 *
	 * Stores transient data in WordPress options table.
	 *
	 * @param string $transient  Transient name.
	 * @param mixed  $value      Transient value.
	 * @param string $group      Transient group ('transient' or 'site-transient').
	 * @param int    $expiration Time until expiration in seconds.
	 * @return bool True on success, false on failure.
	 */
	private function _transient_set( $transient, $value, $group, $expiration ) {
		if ( 'transient' === $group ) {
			/**** Ori WP func start */
			$transient_timeout = '_transient_timeout_' . $transient;
			$transient_option  = '_transient_' . $transient;
			if ( false === get_option( $transient_option ) ) {
				$autoload = 'yes';
				if ( (int) $expiration ) {
					$autoload = 'no';
					add_option( $transient_timeout, time() + (int) $expiration, '', 'no' );
				}
				$result = add_option( $transient_option, $value, '', $autoload );
			} else {
				// If expiration is requested, but the transient has no timeout option,
				// delete, then re-create transient rather than update.
				$update = true;
				if ( (int) $expiration ) {
					if ( false === get_option( $transient_timeout ) ) {
						delete_option( $transient_option );
						add_option( $transient_timeout, time() + (int) $expiration, '', 'no' );
						$result = add_option( $transient_option, $value, '', 'no' );
						$update = false;
					} else {
						update_option( $transient_timeout, time() + (int) $expiration );
					}
				}
				if ( $update ) {
					$result = update_option( $transient_option, $value );
				}
			}
			/**** Ori WP func end */
		} elseif ( 'site-transient' === $group ) {
			/**** Ori WP func start */
			$transient_timeout = '_site_transient_timeout_' . $transient;
			$option            = '_site_transient_' . $transient;
			if ( false === get_site_option( $option ) ) {
				if ( (int) $expiration ) {
					add_site_option( $transient_timeout, time() + (int) $expiration );
				}
				$result = add_site_option( $option, $value );
			} else {
				if ( (int) $expiration ) {
					update_site_option( $transient_timeout, time() + (int) $expiration );
				}
				$result = update_site_option( $option, $value );
			}
			/**** Ori WP func end */
		} else {
			$result = null;
		}

		return $result;
	}

	/**
	 * Delete transient from WP table
	 *
	 * @param string $transient Transient name.
	 * @param string $group     Transient group ('transient' or 'site-transient').
	 */
	private function _transient_del( $transient, $group ) {
		if ( 'transient' === $group ) {
			/**** Ori WP func start */
			$option_timeout = '_transient_timeout_' . $transient;
			$option         = '_transient_' . $transient;
			$result         = delete_option( $option );
			if ( $result ) {
				delete_option( $option_timeout );
			}
			/**** Ori WP func end */
		} elseif ( 'site-transient' === $group ) {
			/**** Ori WP func start */
			$option_timeout = '_site_transient_timeout_' . $transient;
			$option         = '_site_transient_' . $transient;
			$result         = delete_site_option( $option );
			if ( $result ) {
				delete_site_option( $option_timeout );
			}
			/**** Ori WP func end */
		}
	}

        // found returns the value if found (cloned)
        protected function get_from_internal_cache($derived_key, &$found = null)
        {
            if (!array_key_exists($derived_key, $this->cache)) {
                $found = false;
                return false;
            }
            $found = true;
            $value = $this->cache[$derived_key];
            return is_object($value) ? clone $value : $value;
        }

        protected function sanitize_key_part($part)
        {
            return is_string($part) ? str_replace(':', '-', $part) : $part;
        }

        protected function normalize_string($value)
        {
            if (!is_scalar($value)) {
                return '';
            }
            return trim((string) $value);
        }

        protected function normalize_int($value, $default = 0)
        {
            if ($value === '' || $value === null) {
                return (int) $default;
            }
            if (is_numeric($value)) {
                return (int) $value;
            }
            return (int) $default;
        }

        protected function normalize_float($value, $default = 0.0)
        {
            if ($value === '' || $value === null) {
                return (float) $default;
            }
            if (is_numeric($value)) {
                return (float) $value;
            }
            return (float) $default;
        }

        protected function normalize_method($value)
        {
            $method = strtolower($this->normalize_string($value));
            if ($method === 'memcache') {
                $method = 'memcached';
            }
            if (!in_array($method, ['redis', 'memcached'], true)) {
                $method = 'redis';
            }
            return $method;
        }

        protected function normalize_list($value)
        {
            if (is_string($value)) {
                $value = preg_split("/\r\n|\n|\r/", $value);
            }
            if (!is_array($value)) {
                return [];
            }
            $list = [];
            foreach ($value as $item) {
                $item = trim((string) $item);
                if ($item === '') {
                    continue;
                }
                $list[] = $this->sanitize_key_part($item);
            }
            return array_values(array_unique($list));
        }
    }
}
